31	  const nonComponents = step.items.filter((i) => !COMPONENT_TYPES.has(i.type));
32	  const nonComponentTotal = nonComponents.reduce((sum, item) => sum + itemPremium(item), 0);
33	  let componentBase = 0;
34	  if (components.length === 3 && components.every((c) => c.type === components[0].type)) {
35	    componentBase = BLOCK_BASE_PREMIUM;
